pub struct Out {
    pub tag: u64,
    pub ptr: u64,
    pub cap: u64,
}

extern "C" {
    fn __rust_alloc(size: usize, align: usize) -> *mut u8;
    fn __rust_alloc_zeroed(size: usize, align: usize) -> *mut u8;
}

pub fn try_allocate_in(out_result: *mut Out, capacity: i64, zero_init: u8, align: i64, elem_size: i64) {
    let no_alloc_shim_sentinel: *mut u8 = 1usize as *mut u8;
    let padded_elem_size: i64 = elem_size;
    let alloc_size: i64;
    let mul_overflowed: bool;
    let overflow: bool;
    let raw_ptr: *mut u8;
    let alloc_ptr: *mut u8;
    let result_tag: u64;
    let o: u64;

    if capacity == 0 || elem_size == 0 {
        unsafe {
            (*out_result).tag = 0;
            (*out_result).ptr = align as u64;
            (*out_result).cap = 0;
        }
        return;
    }

    let (mul, of_) = (capacity as u64).overflowing_mul(elem_size as u64);
    mul_overflowed = of_;
    alloc_size = mul as i64;
    overflow = mul_overflowed;
    if mul_overflowed {
        unsafe { (*out_result).tag = 1; }
        return;
    }

    raw_ptr = if zero_init != 0 {
        unsafe { __rust_alloc_zeroed(alloc_size as usize, align as usize) }
    } else {
        unsafe { __rust_alloc(alloc_size as usize, align as usize) }
    };

    alloc_ptr = raw_ptr;
    if alloc_ptr == no_alloc_shim_sentinel {
        result_tag = 1;
        o = 0;
    } else {
        result_tag = 0;
        o = alloc_ptr as u64;
    }

    unsafe {
        (*out_result).tag = result_tag;
        (*out_result).ptr = o;
        (*out_result).cap = capacity as u64;
    }
}

fn drop(raw_vec: &mut Box<[u8]>) {
    let _len = raw_vec.len();
    if _len != 0 {
        unsafe {
            std::alloc::dealloc(
                raw_vec.as_mut_ptr(),
                std::alloc::Layout::from_size_align_unchecked(_len, 1),
            );
        }
    }
}

