pub struct Source<'a> {
    pub pos: usize,
    pub src: &'a str,
}

pub fn step(arg2: &Source<'_>) -> String {
    let mut char_vec_alloc: Vec<u32> = arg2.src.chars().map(|cur_codepoint| cur_codepoint as u32).collect();
    let remaining_count = char_vec_alloc.len();
    if remaining_count == 0 {
        return String::new();
    }
    let last_char_1: u32 = char_vec_alloc.pop().unwrap_or(0);
    let mut encoded_str_vec = String::new();
    let mut char_stride: usize = 0;
    while char_stride < char_vec_alloc.len() {
        let cur_codepoint = char_vec_alloc[char_stride];
        encoded_str_vec.push(char::from_u32(cur_codepoint).unwrap_or('\0'));
        char_stride += 1;
    }
    let output_str = step(&Source { pos: 0, src: &encoded_str_vec });
    let mut _ret = String::new();
    _ret.push(char::from_u32(last_char_1).unwrap_or('\0'));
    _ret.push_str(&output_str);
    _ret
}
